### 3. **LLM Driver Creation: `create_driver()` Function**

**File:** `/Users/gaganarora/Desktop/my projects/open_fang/crates/openfang-runtime/src/drivers/mod.rs` (lines 178–317)

```rust
pub fn create_driver(config: &DriverConfig) -> Result<Arc<dyn LlmDriver>, LlmError> {
    let provider = config.provider.as_str();

    // Claude Code (subprocess LLM)
    if provider == "claude-code" {
        return Ok(Arc::new(claude_code::ClaudeCodeDriver));
    }

    // Codex CLI (subprocess LLM)
    if provider == "codex-cli" {
        return Ok(Arc::new(codex_cli::CodexCliDriver));
    }

    // Anthropic (special case — different API format)
    if provider == "anthropic" {
        let (auth_token, use_oauth) = if let Ok(oauth_token) =
            std::env::var("CLAUDE_CODE_OAUTH_TOKEN")
        {
            (oauth_token, true)
        } else {
            (
                config.api_key.clone().ok_or_else(|| {
                    LlmError::MissingApiKey("Anthropic".to_string())
                })?,
                false,
            )
        };
        return Ok(Arc::new(anthropic::AnthropicDriver::new(auth_token, use_oauth)));
    }

    // OpenAI-compatible providers (Groq, DeepSeek, Together, Mistral, Fireworks, etc.)
    let defaults = provider_defaults(provider)?;
    let base_url = config.base_url.as_deref().unwrap_or(&defaults.base_url);
    let api_key = config.api_key.clone().ok_or_else(|| {
        LlmError::MissingApiKey(format!("{} API key required", provider))
    })?;

    Ok(Arc::new(openai::OpenAiDriver {
        base_url: base_url.to_string(),
        api_key,
        provider: provider.to_string(),
    }))
}
```

